const result = JSON.parse($json.output);

return {
  symptoms: $('triage').first().json.body.message,
  urgency: result.urgency,
  category: result.category,
  reasoning: result.reasoning,
  rule_triggered: result.rule_triggered
};

const doctor = $('Find Suitable Doctor').first().json || {};
const webhook = $('Book Appointment Webhook').first().json.body;

return [
  {
    json: {
      patient_symptoms: webhook.symptoms,
      urgency: webhook.urgency,
      category: webhook.category,
      doctor_id: doctor.id || null,
      doctor_name: doctor.name || "Pending assignment",
      doctor_email: doctor.email || "N/A",
      appointment_date: webhook.appointment_date,
      appointment_time: webhook.appointment_time,
      patient_email: webhook.patient_email,
      patient_phone: webhook.patient_phone,
      status: "Confirmed"
    }
  }
];

const appointments = $input.all().map(item => item.json);

return [
  {
    json: {
      success: true,
      appointments
    }
  }
];

const doctors = $input.all()
  .map(item => item.json)
  .filter(row => row && Object.keys(row).length > 0);

return [
  {
    json: {
      success: true,
      doctors
    }
  }
];

const allSlots = [];

for (let hour = 9; hour <= 18; hour++) {
  for (const minute of [0, 30]) {
    if (hour === 18 && minute === 30) continue;

    const h12 = hour > 12 ? hour - 12 : hour;
    const ampm = hour >= 12 ? 'PM' : 'AM';
    const mm = minute === 0 ? '00' : '30';
    allSlots.push(`${h12}:${mm} ${ampm}`);
  }
}

const booked = $input.all()
  .map(item => item.json.appointment_time)
  .filter(Boolean);

return [
  {
    json: {
      success: true,
      available_slots: allSlots.filter(slot => !booked.includes(slot))
    }
  }
];

const appointments = $input.all()
  .map(item => item.json)
  .filter(item => item && item.id);

return [
  {
    json: {
      success: true,
      appointments
    }
  }
];

