const message = $json.message || {};
const text = String(message.text || '').trim();
const chatId = message.chat?.id;
const username = message.chat?.username || null;

const match = text.match(/^\/link(?:@\w+)?\s+([^\s@]+@[^\s@]+\.[^\s@]+)$/i);

if (!chatId || !match) {
  return [
    {
      json: {
        valid: false,
        telegram_chat_id: chatId ? String(chatId) : '',
        patient_email: '',
        telegram_username: username,
        reply: 'Please link your MedCare account using:\n/link your@email.com',
      },
    },
  ];
}

return [
  {
    json: {
      valid: true,
      patient_email: match[1].trim().toLowerCase(),
      telegram_chat_id: String(chatId),
      telegram_username: username,
      reply: `Your MedCare account ${match[1].trim().toLowerCase()} has been connected successfully.`,
    },
  },
];

